import React from "react";
import { useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import "../styles/Cart.css";

const LockIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
    <path d="M7 11V7a5 5 0 0 1 10 0v4" />
  </svg>
);

const ArrowLeftIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" stroke="currentColor" width="16" height="16">
    <path d="M19 12H5M5 12l7 7M5 12l7-7" />
  </svg>
);

const Checkout = () => {
  const { cart, getCartTotal } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  const handlePayment = () => {
    alert("Payment integration coming next step");
  };

  if (cart.items.length === 0) {
    return (
      <div className="checkout-empty">
        <button className="checkout-back-btn" onClick={() => navigate(-1)}>
          <ArrowLeftIcon /> Back
        </button>
        <h2>Your cart is empty</h2>
        <p>Add items to continue</p>
      </div>
    );
  }

  return (
    <div className="checkout-page">

      {/* TOP NAV BAR */}
      <nav className="checkout-navbar">
        <div className="checkout-navbar-inner">
          <span className="checkout-navbar-logo">AURI</span>
        </div>
      </nav>

      <div className="checkout-container">

        {/* BACK BUTTON */}
        <div className="checkout-back-wrapper">
          <button className="checkout-back-btn" onClick={() => navigate(-1)}>
            <ArrowLeftIcon /> Back
          </button>
        </div>

        {/* LEFT SIDE */}
        <div className="checkout-products">
          <h2>Order Summary</h2>

          {cart.items.map((item, index) => (
            <div className="checkout-product" key={index}>
              <img src={item.img} alt={item.title} />
              <div className="checkout-product-info">
                <h4>{item.title}</h4>
                <p>{item.selectedSize} · {item.selectedColor}</p>
                <span>${(parseFloat(item.price) * item.quantity).toFixed(2)}</span>
              </div>
              <div style={{ marginLeft: 'auto', fontSize: '13px', color: '#bbb', alignSelf: 'center' }}>
                ×{item.quantity}
              </div>
            </div>
          ))}
        </div>

        {/* RIGHT SIDE */}
        <div className="checkout-summary">
          <h3>Payment Details</h3>

          <div className="summary-row">
            <span>Email</span>
            <span>{user?.email}</span>
          </div>

          <div className="summary-row">
            <span>Items</span>
            <span>{cart.items.reduce((acc, item) => acc + item.quantity, 0)}</span>
          </div>

          <div className="summary-row total">
            <span>Total</span>
            <span>${getCartTotal().toFixed(2)}</span>
          </div>

          <button className="checkout-pay-btn" onClick={handlePayment}>
            Complete Purchase
          </button>

          <div className="checkout-secure">
            <LockIcon />
            <span>Secure checkout</span>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Checkout;
